#include "captain/sync/sync_service.hpp"
namespace captain::sync {SyncService::SyncService(storage::LocalYamlStorage&l,storage::IRequirementStorage&r,storage::ISnapshotStorage&s):local_(l),remote_(r),snapshots_(s){}Result SyncService::pull(){Result x;for(auto&r:remote_.all()){if(r.type=="CLASS"||r.type=="RISK"||r.type=="CR"||r.type=="SOUP"){++x.unchanged;continue;}local_.write_mirror(r);++x.pulled;}return x;}Result SyncService::push(const std::string&commit,const std::string&actor){Result x;for(auto&r:local_.all()){snapshots_.push_snapshot(r,commit,actor);r.sync_state="synchronized";r.synced_at=commit;r.synced_by=actor;r.synced_revision=commit;local_.update(r);++x.pushed;}return x;}}
